import React, { Component } from 'react';
import axios from 'axios'
import { properties } from '../../properties/properties.js'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import dayGridPlugin from '@fullcalendar/daygrid' // a plugin!
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick
import listPlugin from '@fullcalendar/list'
import Moment from 'moment'

class UploadPayroll extends Component {

   constructor() {
      super();
      var today = new Date();
      this.state = { selectedFile: null, loaded: 0, assignment: [], uploadResponse: [], uploadDay: [], todayDay: today.getDate(), selectedOption: "", monthDay: "", screen: 0};

      //this.handleSubmit = this.handleSubmit.bind(this);
    }

    componentWillMount() {
      //this.callAPI();
      //this.getRainbow();
      //this.setState({uploadDay: Array.from(new Set(res.map(groups => groups.day))).map(group => {return {day: group}})
      this.setState({monthDay: "31"})
      this.setState({screen: 0})
    }

    handleText = e => {
        //console.log(e);
        this.setState({ monthDay: e.target.value });
        //console.log(e.target.value)
    };
    /*
    getRainbow() {    
    var backUrl = properties.backend + `uploadoff`
      fetch(backUrl)       
          .then(res => res.json())        
          .then(res => this.setState({ uploadResponse: res}))
          .catch(err => err);
    }
    */
    /*
    handleSubmit(event) {
      event.preventDefault();
      const data = new FormData(event.target);

      fetch('http://localhost:9000/upload', {
        method: 'POST',
        body: data,
      });
    }*/

    /*
    render() {
       return (
         <form id=  "uploadForm" onSubmit={this.handleSubmit} enctype= "multipart/form-data" >
             <input type="file" name="file" />Upload
             <input type="submit" value="Upload" name="submit"></input>
         </form>
       )
    }
    */

   handleselectedFile = event => {
      this.setState({
        selectedFile: event.target.files[0],
        loaded: 0,
      })
    }


    handleAssignment = (assignment) => {
      this.setState({screen: 3})
      this.setState({assignment: assignment})
    }

    handleBack = () => {
      this.setState({screen: 2})
    }

handleUpload = () => {
    this.setState({screen: 1})
    const data = new FormData()
    data.append('file', this.state.selectedFile, this.state.selectedFile.name)
    data.append('todayDate', this.state.todayDay)
    data.append('monthDay', this.state.monthDay)
    var backUrl = properties.backend + `uploadPayroll`
    axios
      .post(backUrl, data, {
        onUploadProgress: ProgressEvent => {
          this.setState({
            loaded: (ProgressEvent.loaded / ProgressEvent.total*100),
          })
        },
      })
      .then(res => {
        //console.log(res.statusText)
        //console.log(res.data)
        //console.log(res.data.teamData)
        //this.setState({uploadResponse: res.data.data})

        this.setState({uploadResponse: res.data})
        this.setState({screen: 2})
      })
  }





   render() {

    const items = []
/*
    for (let rowNum = 1; rowNum <= 31; rowNum++) {
      var findWeekday = "";

      this.state.uploadResponse.filter(Record => this.returnMatch(Record.day) === rowNum).map(Record => (
        findWeekday = Record.weekday
      ));
      if (this.state.uploadResponse.find(Record => this.returnMatch(Record.day) === rowNum))
          items.push(<div><hr></hr>Day: {rowNum} -  {findWeekday}</div>)
      this.state.uploadResponse.filter(Record => this.returnMatch(Record.day) === rowNum).map(Record => (
          items.push(<div>Team {Record.team}: {Record.duty}</div>)
      ));
    }
*/


    var showDiv = "";

    //this.state.uploadDay.map(Record => (
         //this.inputArrayData(Record.day, items)
    //));
    try {
        /*
      Array.from(new Set(this.state.uploadResponse.map(groups => groups.date))).map(group => {return {date: group}}).map(Record =>(
        this.inputArrayData(Record.date, items)
        //console.dir(Record)
      ))*/

      //   <input type="text" name="" id="" onChange={this.handleText} value={this.state.monthDay}/>

      if (this.state.screen === 0) {
      showDiv =          <div >
      <input type="hidden" name="todayDate" value={this.state.todayDay} />
      <input type="file" name="" id="" onChange={this.handleselectedFile} />


      &nbsp;&nbsp;


      <button onClick={this.handleUpload}>Upload</button>
      <br/><br/>
      <div>Upload Progress: {Math.round(this.state.loaded,2) } %</div>
      <hr></hr>

    </div>
      }


      if (this.state.screen === 1) {
        showDiv = <div>Loading ....</div>
      }

      if (this.state.screen === 3) {
        var content = []
        var name = ""
        var events = []

        for (let x in this.state.assignment) {
          name = this.state.assignment[x].name
          events.push({id: "", groupId: "",title: this.state.assignment[x].assignment + " (" + this.state.assignment[x].start + " -" + this.state.assignment[x].end + " )",  date: Moment(this.state.assignment[x].date).format("YYYY-MM-DD") })
      }

      content.push (<div>Name: {name}</div>)
        content.push(                 <FullCalendar
          plugins={[ dayGridPlugin, interactionPlugin, listPlugin ]}
          initialView="dayGridMonth"
          //eventClick={this.handleEventClick}
          //dateClick={this.handleDateClick}
          eventOrder="id"
          events={events}

        />)

        console.log(this.state.assignment)


        showDiv = <div><button type="button" onClick={data => this.handleBack()}>Back</button><hr>
        </hr>{content}</div>


      }

      if (this.state.screen === 2) {

        var content = []
        var tableContentformat = []

        tableContentformat.push(<tr>
        <td style={{border: "1px solid", padding: "5px"}}>
          name
        </td>
        <td style={{border: "1px solid", padding: "5px"}}>
          UC Path ID
        </td>
        <td style={{border: "1px solid", padding: "5px"}}>
          employee ID
        </td>
        <td style={{border: "1px solid", padding: "5px"}}>
          position number
        </td>
        <td style={{border: "1px solid", padding: "5px"}}>
          Other
        </td>
        <td style={{border: "1px solid", padding: "5px"}}>
          UCSF Clinical
        </td>
        <td style={{border: "1px solid", padding: "5px"}}>
          UCSF NHB/Res
        </td>
        <td style={{border: "1px solid", padding: "5px"}}>
          VA-Res
        </td>
        <td style={{border: "1px solid", padding: "5px"}}>
          ZSFG
        </td>
        <td style={{border: "1px solid", padding: "5px"}}>
          Total Days
        </td>
        <td style={{border: "1px solid", padding: "5px"}}>
          rotation
        </td>
        </tr>)

          //console.log(this.state.uploadResponse)






          if (this.state.uploadResponse.length > 0) {
        this.state.uploadResponse.map(rec =>{


          var daysInMonth = new Date(rec.year, rec.month, 0).getDate()

          if (rec.totalDays != daysInMonth) {
            tableContentformat.push(<tr>
              <td style={{border: "1px solid", padding: "5px"}}>
                {rec.name}
              </td>
              <td style={{border: "1px solid", padding: "5px"}}>
                {rec.UCPathID}
              </td>
              <td style={{border: "1px solid", padding: "5px"}}>
                {rec.employeeID}
              </td>
              <td style={{border: "1px solid", padding: "5px"}}>
              {rec.positionNumber}
              </td>
              <td style={{border: "1px solid", padding: "5px"}}>
              <input type="text" name="" id="" onChange={this.handleText} value={rec.other}/>
              </td>
              <td style={{border: "1px solid", padding: "5px"}}>
              {rec.UCSFClinical}
              </td>
              <td style={{border: "1px solid", padding: "5px"}}>
              {rec.UCSFNHBRes}
              </td>
              <td style={{border: "1px solid", padding: "5px"}}>
              {rec.VARes}
              </td>
              <td style={{border: "1px solid", padding: "5px"}}>
              {rec.ZSFG}
              </td>
              <td style={{border: "1px solid", padding: "5px"}}>
              {rec.totalDays}
              </td>
              <td style={{border: "1px solid", padding: "5px"}}>
                <button type="button" onClick={data => this.handleAssignment(rec.assignment)}>Rotation</button>&nbsp;
              </td>
              </tr>)
          }
        })

      }

        content.push(<table style={{marginTop: "5px"}}>{tableContentformat}</table>)


        showDiv = <div>{content}</div>






      }



    } catch (e) {
      console.log(e)
      showDiv = "You don't have permission for using this application!"
    }




      return (
        <div style={{minHeight: "500px", marginLeft: "50px"}}>{showDiv}</div>
       )
   }
